// ── Field alias maps ─────────────────────────────────────────────────────
const FIELD_ALIAS_DEFS = {
  sn: {
    label: 'Serial Number',
    aliases: ['Serial Number', 'Serial', 'S/N', 'Asset SN', 'Manuf. SN', 'SN'],
    regex: /^(serial\s*number|serial|s\s*\/\s*n|asset\s*sn|manuf\.?\s*sn|sn)$/i,
  },
  model: {
    label: 'Model',
    aliases: ['Display name', 'Model', 'Model name', 'Product Description', 'Material desc', 'Material description', 'Description'],
    regex: /^(display\s*name|model(\s*name)?|product\s*description|material\s*desc(ription)?|description)$/i,
  },
  pn: {
    label: 'Part Number',
    aliases: ['Part Number', 'P/N', 'PN', 'Material Code'],
    regex: /^(part\s*number|p\/n|pn|material\s*code)$/i,
  },
  mtm: {
    label: 'MTM',
    aliases: ['Machine Type Model', 'MTM'],
    regex: /^(machine\s*type\s*model|mtm)$/i,
  },
  account: {
    label: 'Account',
    aliases: ['Account', 'Customer name', 'Legal Entity Name', 'Company', 'Client'],
    regex: /^(account|customer\s*name|legal\s*entity\s*name|company|client)$/i,
  },
  brand: {
    label: 'Brand',
    aliases: ['Brand', 'Make', 'Manufacturer'],
    regex: /^(brand|make|manufacturer)$/i,
  },
  status: {
    label: 'Status',
    aliases: ['Device Status', 'Device Status (Return/Extend/Buyout)', 'EOL Status', 'Status'],
    regex: /^(device\s*status(\s*\(return\/extend\/buyout\))?|eol\s*status|status)$/i,
  },
};
const FIELD_ALIASES = Object.fromEntries(
  Object.entries(FIELD_ALIAS_DEFS).map(([role, def]) => [role, def.regex])
);

function normHeader(s) {
  return String(s || '')
    .replace(/\u00a0/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase();
}

function normalizeSN(s) {
  return String(s || '')
    .replace(/[\u00a0\s]+/g, '')
    .replace(/[-\u2010-\u2015\u2212]/g, '')
    .trim();
}

function isExplicitNonReturnStatus(status) {
  const s = String(status || '')
    .replace(/\u00a0/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase();
  if (!s) return false;
  return /^(extend|extension|renew|renewal|buy\s*out|buyout|keep|retain|retained|non[-\s]*return|not\s*return|not\s*returned|not\s*require\s*to\s*return|cancel|cancelled|canceled)$/i.test(s);
}

function looksLikeReturnStatus(status) {
  const s = String(status || '')
    .replace(/\u00a0/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase();
  return /\breturn\b|buy\s*out|buyout|non[-\s]*return|not\s*require\s*to\s*return|not\s*returned?/i.test(s);
}

function renderFieldAliasTooltip() {
  const list = document.getElementById('fieldAliasList');
  if (!list) return;
  list.innerHTML = Object.values(FIELD_ALIAS_DEFS).map(def =>
    `<dt>${esc(def.label)}</dt><dd>${def.aliases.map(esc).join(', ')}</dd>`
  ).join('');
}

// Skip sheets that are obviously not detail data
const SKIP_SHEET_RE = /pivot|summary|overview|definition|read\s*me|status\s*mean|cover|instruction|p\.?o\b|contract|billing/i;

function detectFieldMap(headers) {
  const map = {};
  headers.forEach(h => {
    const ht = String(h).replace(/\u00a0/g, ' ').trim();
    for (const [role, re] of Object.entries(FIELD_ALIASES)) {
      if (!map[role] && re.test(ht)) map[role] = h;
    }
  });
  return map;
}

function refineFieldMapWithData(data, fm) {
  if (!data || !data.length) return fm;
  const headers = Object.keys(data[0] || {});
  const statusCandidates = headers.filter(h => FIELD_ALIASES.status.test(String(h).trim()));
  if (statusCandidates.length <= 1) return fm;

  let bestHeader = fm.status;
  let bestScore = -1;
  statusCandidates.forEach(h => {
    let score = 0;
    for (let i = 0; i < Math.min(data.length, 500); i++) {
      if (looksLikeReturnStatus(data[i][h])) score += 10;
      else if (isExplicitNonReturnStatus(data[i][h])) score += 5;
    }
    const hn = normHeader(h);
    if (/^(device\s*status|eol\s*status)$/.test(hn)) score += 25;
    if (hn === 'status') score += 5;
    if (score > bestScore) {
      bestScore = score;
      bestHeader = h;
    }
  });

  if (bestHeader) return {...fm, status: bestHeader};
  return fm;
}

function scoreSheet(data) {
  if (!data || !data.length) return 0;
  const headers = Object.keys(data[0] || {});
  const fm = detectFieldMap(headers);
  let score = data.length; // more rows = better
  if (fm.sn)    score += 1000;
  if (fm.model || fm.pn || fm.mtm) score += 500;
  if (fm.account) score += 50;
  return score;
}

// Truncate data at the first gap of GAP_SIZE or more consecutive fully-empty rows.
// This handles files where multiple unrelated tables are stacked in one sheet.
// Must use array-of-arrays (header:1) input so empty rows are not silently dropped.
function trimAtGap(data, gapSize = 3) {
  let emptyRun = 0, gapStart = -1;
  for (let i = 0; i < data.length; i++) {
    const allEmpty = Object.values(data[i]).every(v => v === '' || v === null || v === undefined);
    if (allEmpty) {
      if (emptyRun === 0) gapStart = i;
      emptyRun++;
      if (emptyRun >= gapSize) return data.slice(0, gapStart);
    } else {
      emptyRun = 0; gapStart = -1;
    }
  }
  return data;
}

// Scan the first maxSearch rows and return the index of the row most likely
// to be the real header row (contains the most recognisable field names).
// This lets us skip banner / title rows such as "Asset Recovery Services".
function findHeaderRow(rows, maxSearch = 8) {
  let bestRow = 0, bestScore = -1;
  for (let i = 0; i < Math.min(rows.length, maxSearch); i++) {
    const cells = rows[i].map(v => String(v || '').trim()).filter(Boolean);
    const fm = detectFieldMap(cells);
    const score = (fm.sn ? 100 : 0)
                + (fm.model || fm.pn || fm.mtm ? 50 : 0)
                + (fm.account ? 10 : 0)
                + cells.length;          // tiebreak: more non-empty cells wins
    if (score > bestScore) { bestScore = score; bestRow = i; }
  }
  return bestRow;
}

// Parse a sheet with gap detection.
// Uses header:1 array mode (preserves empty rows) to find the first 3-row gap,
// then slices and re-converts to object rows.
function parseSheetData(ws, XLSXLib, gapSize = 3) {
  const rows = XLSXLib.utils.sheet_to_json(ws, {header: 1, defval: ''});
  if (!rows.length) return [];

  // Skip any title / banner rows above the real header row
  const headerRow = findHeaderRow(rows);
  const workRows = headerRow > 0 ? rows.slice(headerRow) : rows;

  // Find first gap of gapSize consecutive fully-empty rows (skip header at i=0)
  let emptyRun = 0, gapStart = -1;
  for (let i = 1; i < workRows.length; i++) {
    const allEmpty = workRows[i].every(v => v === '' || v === null || v === undefined);
    if (allEmpty) {
      if (emptyRun === 0) gapStart = i;
      emptyRun++;
      if (emptyRun >= gapSize) {
        // Rebuild as objects using only header + rows before gap
        const truncated = workRows.slice(0, gapStart);
        const tmpWs = XLSXLib.utils.aoa_to_sheet(truncated);
        return XLSXLib.utils.sheet_to_json(tmpWs, {defval: ''});
      }
    } else {
      emptyRun = 0; gapStart = -1;
    }
  }
  // No gap
  if (headerRow > 0) {
    const tmpWs = XLSXLib.utils.aoa_to_sheet(workRows);
    return XLSXLib.utils.sheet_to_json(tmpWs, {defval: ''});
  }
  return XLSXLib.utils.sheet_to_json(ws, {defval: ''});
}

// Try to extract a total count from a Pivot/summary sheet.
// Looks for a cell whose value matches "total" / "grand total" and returns the adjacent number.
function extractPivotTotal(ws, XLSXLib) {
  try {
    const rows = XLSXLib.utils.sheet_to_json(ws, {header: 1, defval: ''});
    for (const row of rows) {
      for (let c = 0; c < row.length; c++) {
        if (/^(grand\s*)?total$/i.test(String(row[c]).trim())) {
          // Check right neighbour and all remaining cells in this row for a number
          for (let nc = c + 1; nc < row.length; nc++) {
            const v = Number(row[nc]);
            if (!isNaN(v) && v > 0) return v;
          }
        }
      }
    }
  } catch(e) { /* ignore */ }
  return null;
}

function pickBestSheet(wb) {
  var XLSXLib = _XLSX || window.XLSX;
  let best = null, bestScore = -1, bestName = '';

  // Try to find a pivot/summary sheet to extract expected total for validation
  let pivotTotal = null;
  for (const name of wb.SheetNames) {
    if (/pivot|summary/i.test(name.trim())) {
      pivotTotal = extractPivotTotal(wb.Sheets[name], XLSXLib);
      if (pivotTotal) break;
    }
  }

  for (const name of wb.SheetNames) {
    if (SKIP_SHEET_RE.test(name.trim())) continue;
    const ws = wb.Sheets[name];
    const data = parseSheetData(ws, XLSXLib);   // gap-aware parsing
    const score = scoreSheet(data);
    if (score > bestScore) { bestScore = score; best = data; bestName = name; }
  }
  // Fallback: if all sheets were skipped, just use the first one
  if (!best) {
    const ws = wb.Sheets[wb.SheetNames[0]];
    best = parseSheetData(ws, XLSXLib);
    bestName = wb.SheetNames[0];
  }
  return { data: best, sheetName: bestName, pivotTotal };
}

// Current workbook field map (set after parsing, used by manual mapping UI)
let _currentWb = null;
let _currentFname = '';
let _currentSheetName = '';
let _lastParsedSummaryHtml = '';

function toggleSnGroup(header) {
  const arrow = header.querySelector('.sn-group-arrow');
  const tags  = header.nextElementSibling;
  if (!tags) return;
  const open = tags.classList.toggle('open');
  if (arrow) arrow.classList.toggle('open', open);
}

function processFile(file) {
  const dz = document.getElementById("dropZone");
  const bar = document.getElementById("uploadBar");
  const summary = document.getElementById("summary");
  // Reset collapsed state while loading
  if (dz) dz.classList.remove("hidden");
  if (bar) bar.classList.add("hidden");
  const uploadRow = document.getElementById("step1UploadRow");
  if (uploadRow) uploadRow.classList.remove("hidden");
  // Always hide the manual-mapping panel at the start of a new upload
  const mapBox = document.getElementById('manualMapBox');
  if (mapBox) mapBox.classList.add('hidden');
  dz.classList.add("drag");
  summary.innerHTML = '<div class="summary-box" style="color:#666">&#9203; Reading file&hellip;</div>';

  const reader = new FileReader();
  reader.onload = e => {
    try {
      var XLSXLib = _XLSX || window.XLSX;
      if (!XLSXLib || !XLSXLib.read) throw new Error("SheetJS library not loaded — please reload the page.");
      const wb = XLSXLib.read(new Uint8Array(e.target.result), {type:"array", cellDates:true});
      _currentWb = wb;
      _currentFname = file.name;
      const { data, sheetName, pivotTotal } = pickBestSheet(wb);
      _currentSheetName = sheetName || '';
      if (!data.length) throw new Error("No data rows found in the file.");
      const fm = refineFieldMapWithData(data, detectFieldMap(Object.keys(data[0] || {})));
      if (!fm.sn) {
        // Can't auto-detect — show manual mapping UI
        showManualMapping(wb, file.name, sheetName, 'auto');
        return;
      }
      onParsed(data, file.name, sheetName, fm, pivotTotal);
    } catch(err) {
      summary.innerHTML = '<div class="summary-box" style="background:#fff0f0;border-color:#ffaaaa;color:#cc0000">&#10060; Could not read file: ' + err.message + '</div>';
    } finally {
      dz.classList.remove("drag");
    }
  };
  reader.onerror = () => {
    summary.innerHTML = '<div class="summary-box" style="background:#fff0f0;border-color:#ffaaaa;color:#cc0000">&#10060; File read error. Please try again.</div>';
    dz.classList.remove("drag");
  };
  reader.readAsArrayBuffer(file);
}

function openManualMapping() {
  if (!_currentWb) {
    alert('Please upload an .xlsx file first.');
    return;
  }
  const summary = document.getElementById('summary');
  if (summary && summary.innerHTML.trim()) _lastParsedSummaryHtml = summary.innerHTML;
  showManualMapping(_currentWb, _currentFname, _currentSheetName, 'manual');
  const box = document.getElementById('manualMapBox');
  if (box) box.scrollIntoView({behavior:'smooth', block:'nearest'});
}

function cancelManualMapping() {
  const box = document.getElementById('manualMapBox');
  if (box) box.classList.add('hidden');
  const summary = document.getElementById('summary');
  if (summary && _lastParsedSummaryHtml) summary.innerHTML = _lastParsedSummaryHtml;
}

function showManualMapping(wb, fname, defaultSheetName, mode = 'auto') {
  var XLSXLib = _XLSX || window.XLSX;
  const box = document.getElementById('manualMapBox');
  box.classList.remove('hidden');

  // Populate sheet selector
  const sheetSel = document.getElementById('mm_sheet');
  sheetSel.innerHTML = '';
  wb.SheetNames.forEach(n => {
    const opt = document.createElement('option'); opt.value = n; opt.textContent = n;
    sheetSel.appendChild(opt);
  });
  // Default to the best sheet already found by pickBestSheet, not necessarily [0]
  if (defaultSheetName && wb.SheetNames.includes(defaultSheetName)) {
    sheetSel.value = defaultSheetName;
  }

  function populateCols() {
    const ws = wb.Sheets[sheetSel.value];
    const data = parseSheetData(ws, XLSXLib);
    const headers = data.length ? Object.keys(data[0]) : [];
    ['mm_sn','mm_modelpn','mm_account','mm_status'].forEach((id, i) => {
      const sel = document.getElementById(id);
      const first = sel.options[0].text; // keep "— select —" or "— (none) —"
      sel.innerHTML = `<option value="">${first}</option>`;
      headers.forEach(h => {
        const opt = document.createElement('option'); opt.value = h; opt.textContent = h;
        sel.appendChild(opt);
      });
      // Auto-suggest based on aliases
      const suggested = id === 'mm_modelpn'
        ? headers.find(h => FIELD_ALIASES.model.test(h.trim()))
          || headers.find(h => FIELD_ALIASES.pn.test(h.trim()))
          || headers.find(h => FIELD_ALIASES.mtm.test(h.trim()))
        : headers.find(h => FIELD_ALIASES[
            id === 'mm_sn' ? 'sn' :
            id === 'mm_account' ? 'account' :
            'status'
          ].test(h.trim()));
      if (suggested) sel.value = suggested;
    });
  }
  sheetSel.onchange = populateCols;
  populateCols();

  const summaryText = mode === 'manual'
    ? '&#9881; Manual mapping mode. Select a sheet and columns, then apply to re-parse this file.'
    : '&#9888; Fields could not be auto-detected. Please map columns below.';
  document.getElementById('summary').innerHTML =
    '<div class="summary-box" style="color:#856404">' + summaryText + '</div>';
}

function applyManualMapping() {
  const wb = _currentWb;
  if (!wb) return;
  var XLSXLib = _XLSX || window.XLSX;
  const sheetName = document.getElementById('mm_sheet').value;
  const ws = wb.Sheets[sheetName];
  const data = parseSheetData(ws, XLSXLib);
  const modelPn = document.getElementById('mm_modelpn').value || null;
  const fm = {
    sn:      document.getElementById('mm_sn').value      || null,
    model:   modelPn,
    pn:      modelPn,
    account: document.getElementById('mm_account').value || null,
    status:  document.getElementById('mm_status').value  || null,
  };
  if (!fm.sn) {
    alert('Please select Serial Number column.');
    return;
  }
  _currentSheetName = sheetName || '';
  document.getElementById('manualMapBox').classList.add('hidden');
  onParsed(data, _currentFname, sheetName, fm);
}

function onParsed(data, fname, sheetName, fm, pivotTotal) {
  // Always ensure the manual-mapping panel is hidden when we have a valid parse
  const mapBox = document.getElementById('manualMapBox');
  if (mapBox) mapBox.classList.add('hidden');
  // fm = field map from detectFieldMap; if called without fm (legacy), auto-detect
  if (!fm) fm = refineFieldMapWithData(data, detectFieldMap(Object.keys(data[0] || {})));
  if (!sheetName) sheetName = '';
  _currentSheetName = sheetName;

  const get = (row, role) => {
    const key = fm[role];
    if (!key) return '';
    let val = row[key];
    if ((val === undefined || val === null) && row && typeof row === 'object') {
      const wanted = normHeader(key);
      const actualKey = Object.keys(row).find(k => normHeader(k) === wanted);
      if (actualKey) val = row[actualKey];
    }
    const out = String(val || '').trim();
    return role === 'sn' ? normalizeSN(out) : out;
  };

  const inputRowCount = data.length;
  let rows = data;

  // Use an exclusion model for status: remove only rows clearly marked as
  // non-return, and keep blank / unknown statuses for user review.
  const hasStatusColumn = !!fm.status;
  if (hasStatusColumn) rows = rows.filter(r => !isExplicitNonReturnStatus(get(r, 'status')));
  const statusFilteredCount = inputRowCount - rows.length;

  const noSnCount = rows.filter(r => !get(r, 'sn')).length;
  rows = rows.filter(r => get(r, 'sn'));

  allSNs = rows.map(r => get(r, 'sn')).filter(Boolean);
  // Dedupe while preserving order
  const snSet = new Set();
  allSNs = allSNs.filter(s => { if(snSet.has(s)) return false; snSet.add(s); return true; });

  const accts = [...new Set(rows.map(r => get(r, 'account')).filter(Boolean))];
  if(accts[0]) document.getElementById("f_account").value = accts[0];
  (function(){
    const a=(accts[0]||'ARS').replace(/[^\w\-]/g,'_').slice(0,30);
    const d=new Date().toISOString().slice(0,10);
    const el=document.getElementById('genNoteFilename');
    if(el) el.textContent=`ARS_Template_${a}_${d}.xlsx`;
  })();

  const groups = {};
  rows.forEach((r, i) => {
    const sn    = get(r, 'sn');
    let   model = get(r, 'model');
    const pn    = get(r, 'pn');
    const mtm   = get(r, 'mtm');
    const brand = get(r, 'brand');

    // Strip SN prefix embedded in Display name, e.g. "F0JYR9JN7M - APPLE-SSG Apple iPad..."
    // This happens in ALM exports where Display name = "{SN} - {model description}"
    if (sn && model.toUpperCase().startsWith(sn.toUpperCase())) {
      model = model.slice(sn.length).replace(/^\s*[-–—]\s*/, '').trim();
    }

    // Group key priority: MTM > PN > model display name.
    // If the input only has SN, keep one provisional row per SN and let spec lookup
    // backfill productName / MTM later.
    const key = mtm || pn || model || (sn ? `__sn_only__${sn}` : '');
    if (!key) return;
    if (!groups[key]) groups[key] = {
      model: model || mtm || pn || 'Pending Lenovo lookup',
      mtm: mtm || pn,
      count: 0,
      sns: [],
      brand,
      snOnly: !(model || mtm || pn)
    };
    groups[key].count++;
    if (sn) groups[key].sns.push(sn);
  });

  // Warn about empty/duplicate SNs
  const emptySNCount = noSnCount;
  const dupSNCount   = rows.filter(r => get(r, 'sn')).length - allSNs.length;
  let warnings = '';
  if (hasStatusColumn && statusFilteredCount) warnings += `<div style="color:#856404">&#9888; ${statusFilteredCount} explicit non-return row(s) were excluded.</div>`;
  if (emptySNCount) warnings += `<div style="color:#856404">&#9888; ${emptySNCount} row(s) have no Serial Number and were skipped.</div>`;
  if (dupSNCount)   warnings += `<div style="color:#856404">&#9888; ${dupSNCount} duplicate SN(s) removed.</div>`;

  const sheetInfo = sheetName ? ` &mdash; Sheet: <em>${sheetName}</em>` : '';
  const parsedSummaryHtml = `
    <div class="summary-box">
      <div class="summary-head">
        <h3>&#10003; Parsed${sheetInfo}</h3>
        <button class="summary-map-btn" id="mapFieldsBtn" onclick="openManualMapping()"><svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.3" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-1px"><line x1="4" y1="21" x2="4" y2="14"/><line x1="4" y1="10" x2="4" y2="3"/><line x1="12" y1="21" x2="12" y2="12"/><line x1="12" y1="8" x2="12" y2="3"/><line x1="20" y1="21" x2="20" y2="16"/><line x1="20" y1="12" x2="20" y2="3"/><line x1="1" y1="14" x2="7" y2="14"/><line x1="9" y1="8" x2="15" y2="8"/><line x1="17" y1="16" x2="23" y2="16"/></svg>Change Mapping</button>
      </div>
      ${warnings}
      <div class="summary-grid">
        <div class="s-item"><div class="val">${rows.length}</div><div class="lbl">Total Assets</div></div>
        <div class="s-item"><div class="val">${Object.keys(groups).length}</div><div class="lbl">Unique Models</div></div>
        <div class="s-item"><div class="val">${allSNs.length}</div><div class="lbl">Serial Numbers</div></div>
        <div class="s-item"><div class="val">${accts.length}</div><div class="lbl">Account(s)</div></div>
      </div>
    </div>`;
  _lastParsedSummaryHtml = parsedSummaryHtml;
  document.getElementById("summary").innerHTML = parsedSummaryHtml;
  document.getElementById("ptbody").innerHTML = "";
  rowIdx = 0;
  const groupList = Object.values(groups);
  const snDetailSeen = new Set();
  allSNRows = [];
  groupList.forEach(g => {
    const modelPart = [g.model, g.mtm]
      .filter(Boolean)
      .filter((v, i, arr) => arr.findIndex(x => String(x).toLowerCase() === String(v).toLowerCase()) === i)
      .join(' ');
    g.sns.forEach(sn => {
      if (!sn || snDetailSeen.has(sn)) return;
      snDetailSeen.add(sn);
      allSNRows.push({ model: modelPart || g.model || g.mtm || '', sn });
    });
  });
  groupList.forEach(g => addRow(g, { skipSerialRefresh: true }));

  refreshSerialNumberGroups();

  // Collapse upload area into bar
  const dz = document.getElementById('dropZone');
  const bar = document.getElementById('uploadBar');
  const barName = document.getElementById('uploadBarName');
  if (dz && bar && barName) {
    dz.classList.add('hidden');
    barName.textContent = fname;
    bar.classList.remove('hidden');
  }

  ["s2","s3","s4"].forEach(id => document.getElementById(id).classList.remove("hidden"));
  // Show floating generate button only if user is on Tab 1 (Pick-up Request Generator)
  try {
    const fab = document.getElementById("fabGen");
    const activePane = document.querySelector('.tab-pane.active');
    if (fab && activePane && activePane.id === 't1') {
      // only show when on t1 and there are product rows
      const hasRows = document.querySelectorAll('#ptbody tr').length > 0;
      if (hasRows) fab.classList.add("visible");
    }
  } catch(e) { console.warn('fab visibility check failed', e); }
  document.getElementById("s2").scrollIntoView({behavior:"smooth"});
  // Auto-fetch specs for all Lenovo rows in background
  setTimeout(() => autoFetchAllSpecs(), 400);
}

function detectPT(model) {
  const m = model.toLowerCase();
  if(m.includes("ipad")||m.includes("tablet")) return "Tablet";
  if(m.includes("iphone")||(/phone|smartphone/i).test(m)) return "Mobile/Smart Phone";
  if(m.includes("macbook")||m.includes("thinkpad")||m.includes("thinkbook")||m.includes("ideapad")||m.includes("laptop")||m.includes("notebook")) return "Notebook/Laptop";
  if(m.includes("thinkcentre")||m.includes("ideacentre")||m.includes("desktop")||m.includes("mac mini")) return "Desktop";
  if(m.includes("thinkvision")||m.includes("monitor")||m.includes("display")) return "Flat Panel Display/Monitor";
  if(m.includes("thinkstation")||m.includes("workstation")||m.includes("imac")||m.includes("all in one")||m.includes("aio")) return "All in One / Workstation / Apple MacPro (<13.6 kg)";
  return "Notebook/Laptop";
}

function detectMfr(model) {
  const m = model.toLowerCase();
  if(m.includes("apple")||m.includes("ipad")||m.includes("iphone")||m.includes("macbook")||m.includes("imac")||m.includes("mac mini")) return "Apple";
  if(m.includes("dell")) return "Dell";
  if(m.includes(" hp ")||m.includes("hewlett")||(/^hp /i).test(model)) return "HP";
  if(m.includes("microsoft")||m.includes("surface")) return "Microsoft";
  if(m.includes("samsung")) return "Samsung";
  if(m.includes("acer")) return "Acer";
  if(m.includes("asus")) return "Asus";
  if(m.includes("lenovo")||m.includes("thinkpad")||m.includes("thinkcentre")||m.includes("ideapad")||m.includes("thinkbook")||m.includes("thinkstation")) return "Lenovo";
  return "Lenovo";
}

function esc(s){return String(s).replace(/&/g,"&amp;").replace(/"/g,"&quot;").replace(/</g,"&lt;");}

function addRow(g, opts) {
  opts = opts || {};
  const idx = rowIdx++;
  const model = g?g.model:"";
  const qty   = g?g.count:1;
  const sns   = g?g.sns:[];
  const mfr   = detectMfr(model);
  const pt    = detectPT(model);
  const isLen = mfr==="Lenovo";
  const seqNum = idx + 1;

  const ptSel  = PT_OPTS.map(o=>`<option${o===pt?" selected":""}>${o}</option>`).join("");
  const grSel  = GRADE_OPTS.map(o=>`<option>${o}</option>`).join("");

  const tr = document.createElement("tr");
  tr.dataset.idx = idx;
  tr.dataset.sns  = JSON.stringify(sns);
  tr.innerHTML = `
    <td class="col-sticky-l col-seq" style="left:0">${seqNum}</td>
    <td class="col-sticky-l col-product-type" style="left:36px"><select class="f-pt" title="${esc(pt)}">${ptSel}</select></td>
    <td><input type="text" class="f-mfr" value="${esc(mfr)}"></td>
    <td><input type="text" class="f-model" value="${esc(model)}"></td>
    <td><input type="number" class="f-qty" value="${qty}" min="1"></td>
    <td><select class="f-grade">${grSel}</select></td>
    <td><input type="text" class="f-year"></td>
    <td><input type="text" class="f-proc"></td>
    <td><input type="number" class="f-pqty" min="1"></td>
    <td><input type="text" class="f-mem"></td>
    <td><input type="number" class="f-mqty" min="1"></td>
    <td><input type="text" class="f-dtype"></td>
    <td><input type="text" class="f-dsize"></td>
    <td><input type="number" class="f-dqty" min="1"></td>
    <td><input type="text" class="f-gpu"></td>
    <td><input type="number" class="f-gqty" min="1"></td>
    <td class="col-sticky-r" style="right:46px">
      <div class="spec-cell">
        <span class="badge ${isLen?"b-pend":"b-na"}" id="bs-${idx}">${isLen?"Pending":"N/A"}</span>
        ${isLen?`<button class="fetch-btn" onclick="fetchSpecs(${idx})">&#128269; Fetch</button>`:""}
      </div>
    </td>
    <td class="col-sticky-r" style="right:0"><button class="del-btn" onclick="removeProductRow(this)">&#x2715;</button></td>
  `;
  document.getElementById("ptbody").appendChild(tr);
  if (!opts.skipSerialRefresh) {
    refreshProductRowNumbers();
    refreshSerialNumberGroups();
  }
}

function refreshSerialNumberGroups() {
  const snListEl = document.getElementById("snList");
  const snCntEl = document.getElementById("snCnt");
  if (!snListEl) return;

  const groups = [...document.querySelectorAll('#ptbody tr')].map((tr, gi) => {
    let sns = [];
    try { sns = JSON.parse(tr.dataset.sns || '[]'); } catch(e) { sns = []; }
    if (sns.length) syncRowQtyWithSerialNumbers(tr, sns);
    const model = ((tr.querySelector('.f-model') || {}).value || '').trim();
    const mtm = (tr.dataset.mtm || '').trim();
    return { idx: tr.dataset.idx, label: model || mtm || `Group ${gi + 1}`, sns };
  });

  const count = groups.reduce((sum, g) => sum + g.sns.length, 0);
  if (snCntEl) snCntEl.textContent = `(${count})`;
  snListEl.innerHTML = groups.map(g => {
    const tags = [
      ...(g.sns.length ? g.sns.map((s, si) => `<div class="sn-tag">
          <span class="sn-tag-text" onclick="editSerialNumberTag(this, ${g.idx}, ${si})">${esc(s)}</span>
          <button class="sn-del" title="Delete SN" onclick="deleteSerialNumber(${g.idx}, ${si})">&times;</button>
        </div>`) : ['<div class="sn-empty">No serial numbers assigned.</div>']),
      `<span class="sn-add-wrap">
        <input class="sn-edit" placeholder="Add SNs"
          onkeydown="if(event.key==='Enter'){event.preventDefault();appendRowSerialNumbers(${g.idx}, this)}">
        <button class="sn-add-btn" onclick="appendRowSerialNumbers(${g.idx}, this.previousElementSibling)">Add</button>
      </span>`
    ].join('');
    return `<div class="sn-group">
      <div class="sn-group-header" onclick="toggleSnGroup(this)">
        <span class="sn-group-title">${esc(g.label)}</span>
        <span class="sn-group-cnt">${g.sns.length} SN${g.sns.length!==1?'s':''}</span>
        <span class="sn-group-arrow">&#9654;</span>
      </div>
      <div class="sn-group-tags">${tags}</div>
    </div>`;
  }).join('');
}

function syncRowQtyWithSerialNumbers(tr, sns) {
  const qty = tr && tr.querySelector ? tr.querySelector('.f-qty') : null;
  if (qty && sns && sns.length) qty.value = sns.length;
}

function updateRowSerialNumbers(idx, value) {
  const tr = document.querySelector(`tr[data-idx="${idx}"]`);
  if (!tr) return;
  const sns = String(value || '')
    .split(/[,\s;]+/)
    .map(normalizeSN)
    .filter(Boolean)
    .filter((sn, i, arr) => arr.indexOf(sn) === i);
  tr.dataset.sns = JSON.stringify(sns);
  syncRowQtyWithSerialNumbers(tr, sns);
  refreshSerialNumberGroups();
}

function appendRowSerialNumbers(idx, input) {
  if (!input) return;
  const additions = String(input.value || '')
    .split(/[,\s;]+/)
    .map(normalizeSN)
    .filter(Boolean);
  if (!additions.length) return;
  const existing = getRowSerialNumbers(idx);
  setRowSerialNumbers(idx, existing.concat(additions));
}

function getRowSerialNumbers(idx) {
  const tr = document.querySelector(`tr[data-idx="${idx}"]`);
  if (!tr) return [];
  try { return JSON.parse(tr.dataset.sns || '[]'); } catch(e) { return []; }
}

function setRowSerialNumbers(idx, sns) {
  const tr = document.querySelector(`tr[data-idx="${idx}"]`);
  if (!tr) return;
  const clean = sns.map(normalizeSN).filter(Boolean).filter((sn, i, arr) => arr.indexOf(sn) === i);
  tr.dataset.sns = JSON.stringify(clean);
  syncRowQtyWithSerialNumbers(tr, clean);
  refreshSerialNumberGroups();
}

function editSerialNumberTag(span, idx, snIndex) {
  const oldValue = span.textContent || '';
  const input = document.createElement('input');
  input.className = 'sn-tag-input';
  input.value = oldValue;
  input.onclick = e => e.stopPropagation();
  input.onkeydown = e => {
    if (e.key === 'Enter') { e.preventDefault(); saveSerialNumberEdit(input, idx, snIndex); }
    if (e.key === 'Escape') refreshSerialNumberGroups();
  };
  input.onblur = () => saveSerialNumberEdit(input, idx, snIndex);
  span.replaceWith(input);
  input.focus();
  input.select();
}

function saveSerialNumberEdit(input, idx, snIndex) {
  const sns = getRowSerialNumbers(idx);
  sns[snIndex] = input.value;
  setRowSerialNumbers(idx, sns);
}

function deleteSerialNumber(idx, snIndex) {
  const sns = getRowSerialNumbers(idx);
  sns.splice(snIndex, 1);
  setRowSerialNumbers(idx, sns);
}

// In-session spec cache: model/pn key → spec result
const _specCache = {};

function hasRealSpec(specs) {
  return !!(specs && (specs.processor || specs.memory || specs.driveType || specs.gpu));
}

function rememberSpecCache(keys, specs) {
  if (!specs) return;
  keys.filter(Boolean).forEach(k => { _specCache[k] = specs; });
}

function extractLikelyLenovoMtms(text) {
  const out = [];
  const s = String(text || '').toUpperCase();
  const matches = s.match(/\b(?:20|21|22|23)[A-Z0-9]{8,10}\b/g) || [];
  matches.forEach(m => { if (!out.includes(m)) out.push(m); });
  return out;
}

function addLookupKey(keys, value) {
  const raw = String(value || '').trim();
  if (!raw) return;
  extractLikelyLenovoMtms(raw).forEach(k => keys.push(k));
  if (!/\s/.test(raw) && raw.length <= 160) keys.push(raw.toUpperCase());
}

function getProductLookupKeys(tr) {
  const keys = [];
  addLookupKey(keys, tr.dataset.mtm || '');
  addLookupKey(keys, tr.dataset.productId || '');
  addLookupKey(keys, ((tr.querySelector('.f-model') || {}).value || ''));
  return keys.filter((k, i, arr) => k && arr.indexOf(k) === i);
}

function ensurePasteSpecButton(tr, idx) {
  if (!tr || tr.querySelector('.paste-spec-btn')) return;
  const cell = tr.querySelector('.spec-cell');
  if (!cell) return;
  const pb = document.createElement('button');
  pb.className = 'fetch-btn paste-spec-btn';
  pb.style.cssText = 'margin-top:0';
  pb.innerHTML = '&#128203; Paste Spec';
  pb.onclick = () => openSpecModal(idx);
  cell.appendChild(pb);
}

// Auto-fetch specs for every pending Lenovo row, concurrently (max 4 at a time)
async function autoFetchAllSpecs() {
  const rows = [...document.querySelectorAll('#ptbody tr')].filter(tr => {
    const b = document.getElementById('bs-'+tr.dataset.idx);
    return b && b.classList.contains('b-pend');
  });
  if (!rows.length) return;

  const statusEl = document.getElementById('specFetchStatus');
  statusEl.style.display = 'block';
  // reset bar
  const sfpBarEl = document.getElementById('sfpBar');
  if (sfpBarEl) { sfpBarEl.style.width='0%'; sfpBarEl.style.background='#0066cc'; }
  let done = 0, succeed = 0;
  const total = rows.length;

  const updateStatus = () => {
    const pct = total ? Math.round(done / total * 100) : 0;
    const failed = done - succeed;
    const sfpBar = document.getElementById('sfpBar');
    const sfpLabel = document.getElementById('sfpLabel');
    if (sfpBar) sfpBar.style.width = pct + '%';
    if (done < total) {
      if (sfpLabel) sfpLabel.innerHTML =
        `<span class="spinner"></span>Auto-fetching specs <strong>${done}/${total}</strong> done, <strong style="color:#1a8a1a">${succeed}</strong> succeeded`;
    } else {
      if (failed === 0) {
        if (sfpLabel) sfpLabel.innerHTML = `<span style="color:#1a8a1a;font-size:15px">&#10003;</span>&ensp;<strong>All ${done} model spec(s) fetched successfully.</strong>`;
        if (sfpBar) sfpBar.style.background = '#1a8a1a';
      } else if (succeed === 0) {
        if (sfpLabel) sfpLabel.innerHTML = `<span style="color:#cc6600">&#9888;</span>&ensp;<strong>Auto-fetch blocked (Lenovo WAF).</strong> Click <strong>Paste Spec</strong> on each row to enter specs manually.`;
        if (sfpBar) sfpBar.style.background = '#cc6600';
      } else {
        if (sfpLabel) sfpLabel.innerHTML = `<span style="color:#1a8a1a">&#10003;</span>&ensp;<strong>${succeed} fetched.</strong>&ensp;<span style="color:#cc6600">&#9888; ${failed} blocked — click <strong>Paste Spec</strong> to fill manually.</span>`;
        if (sfpBar) { sfpBar.style.width = (succeed/total*100)+'%'; sfpBar.style.background='#1a8a1a'; }
      }
    }
  };

  updateStatus();

  const CONCURRENCY = 4;
  let i = 0;
  async function runNext() {
    if (i >= rows.length) return;
    const tr = rows[i++];
    const idx = parseInt(tr.dataset.idx);
    const fetchResult = await fetchSpecs(idx);
    done++;
    const b = document.getElementById('bs-'+idx);
    if (fetchResult === 'ok' || fetchResult === 'cache') succeed++;
    else if (b && (b.classList.contains('b-ok') || b.classList.contains('b-cache'))) succeed++;
    updateStatus();
    await runNext();
  }

  const workers = [];
  for (let w = 0; w < Math.min(CONCURRENCY, rows.length); w++) workers.push(runNext());
  await Promise.all(workers);
}

async function fetchSpecs(idx) {
  const tr = document.querySelector(`tr[data-idx="${idx}"]`);
  if(!tr) return 'missing';
  if(tr.dataset.fetching==='1') return 'busy';   // prevent concurrent fetch on same row
  tr.dataset.fetching = '1';
  const sns = JSON.parse(tr.dataset.sns||"[]");
  if(!sns.length){ tr.dataset.fetching='0'; alert("No serial number available for this group."); return 'no-sn'; }

  const btn   = tr.querySelector(".fetch-btn");
  const badge = document.getElementById("bs-"+idx);
  badge.className="badge b-load";
  badge.innerHTML = '<span class="spinner"></span> Loading';
  if(btn){btn.disabled=true; btn.textContent='Fetching';}

  // Check cache first — prefer PN/MTM/productId cache, then model-name cache.
  const modelKey = ((tr.querySelector('.f-model')||{}).value||'').trim().toLowerCase();
  const productLookupKeys = getProductLookupKeys(tr);
  const cacheKeys = [
    ...productLookupKeys.map(k => 'lookup:' + k.toLowerCase()),
    modelKey ? 'model:' + modelKey : ''
  ].filter(Boolean);
  let specs = null;
  for (const ck of cacheKeys) {
    if (_specCache[ck] && hasRealSpec(_specCache[ck])) {
      specs = _specCache[ck];
      break;
    }
  }
  let fromCache = !!specs;
  let metadataCandidate = null;

  if (!specs) {
    // Prefer product-level lookup first. This avoids trying every SN when
    // the input already provides PN / MTM.
    for (let pi = 0; pi < productLookupKeys.length; pi++) {
      const key = productLookupKeys[pi];
      badge.innerHTML = '<span class="spinner"></span> Trying PN/MTM';
      badge.title = 'Trying product key ' + key;
      await new Promise(resolve => requestAnimationFrame(resolve));
      const productSpecs = await queryLenovo(key);
      if (productSpecs) {
        if(productSpecs._productId) tr.dataset.productId=productSpecs._productId;
        if(productSpecs._mtm) tr.dataset.mtm=productSpecs._mtm;
        if(productSpecs._productName) tr.dataset.productName=productSpecs._productName;
        rememberSpecCache(['lookup:' + key.toLowerCase()], productSpecs);
        if (hasRealSpec(productSpecs)) {
          specs = productSpecs;
          break;
        }
        metadataCandidate = metadataCandidate || productSpecs;
      }
    }
  }

  if (!specs) {
    // Try each SN in the group until one returns specs
    for(let si=0; si<sns.length; si++){
      badge.innerHTML='<span class="spinner"></span> Trying '+(si+1)+"/"+sns.length;
      badge.title = 'Trying serial number ' + sns[si];
      await new Promise(resolve => requestAnimationFrame(resolve));
      const snSpecs = await queryLenovo(sns[si]);
      if(snSpecs){
        if(snSpecs._productId) tr.dataset.productId=snSpecs._productId;
        if(snSpecs._mtm) tr.dataset.mtm=snSpecs._mtm;
        if(snSpecs._productName) tr.dataset.productName=snSpecs._productName;
        rememberSpecCache(['sn:' + String(sns[si]).toLowerCase()], snSpecs);
        if (hasRealSpec(snSpecs)) {
          specs = snSpecs;
          break;
        }
        metadataCandidate = metadataCandidate || snSpecs;
        break;
      }
    }
    if (!specs && metadataCandidate) specs = metadataCandidate;
    // Store real specs under all stable row keys for later rows.
    if (specs && hasRealSpec(specs)) rememberSpecCache(cacheKeys, specs);
  }

  if(specs){
    if(specs._productId) tr.dataset.productId = specs._productId;
    if(specs._mtm)       tr.dataset.mtm        = specs._mtm;
    if(specs._productName) tr.dataset.productName = specs._productName;
    const modelInput = tr.querySelector(".f-model");
    if(modelInput && specs._productName && (!modelInput.value || /^Pending Lenovo lookup$/i.test(modelInput.value.trim()))) {
      modelInput.value = specs._productName;
    }
    if(specs.processor) tr.querySelector(".f-proc").value  = specs.processor;
    if(specs.procQty)   tr.querySelector(".f-pqty").value  = specs.procQty;
    if(specs.memory)    tr.querySelector(".f-mem").value   = specs.memory;
    if(specs.memQty)    tr.querySelector(".f-mqty").value  = specs.memQty;
    if(specs.driveType) tr.querySelector(".f-dtype").value = specs.driveType;
    if(specs.driveSize) tr.querySelector(".f-dsize").value = specs.driveSize;
    if(specs.driveQty)  tr.querySelector(".f-dqty").value  = specs.driveQty;
    if(specs.gpu)       tr.querySelector(".f-gpu").value   = specs.gpu;
    if(specs.gpuQty)    tr.querySelector(".f-gqty").value  = specs.gpuQty;
    if(specs.year)      tr.querySelector(".f-year").value  = specs.year;
    if (specs._metadataOnly) {
      badge.textContent = "Identified";
      badge.className = "badge b-id";
      badge.title = "Product name / MTM found; hardware specs still need Retry or Paste Spec";
      ensurePasteSpecButton(tr, idx);
    } else {
      badge.textContent = fromCache ? "Cached" : "Done";
      badge.className   = fromCache ? "badge b-cache" : "badge b-ok";
      badge.title = fromCache ? "Loaded from this page session cache" : "Spec lookup completed";
    }
    mergeDuplicateProductRow(tr);
    refreshSerialNumberGroups();
    if(btn){btn.disabled=false; btn.innerHTML="&#128260; Retry";}
    tr.dataset.fetching = '0';
    return fromCache ? 'cache' : (specs._metadataOnly ? 'identified' : 'ok');
  } else {
    badge.innerHTML = '<span style="color:#cc0000;font-size:11px">&#9888; Not found</span>';
    badge.className = "badge b-err";
    badge.title = "No spec found from available serial numbers";
    ensurePasteSpecButton(tr, idx);
  }
  if(btn){btn.disabled=false; btn.innerHTML="&#128260; Retry";}
  tr.dataset.fetching = '0';
  return 'error';
}

async function queryLenovo(sn) {
  const snU = sn.toUpperCase().trim();

  // ── Priority 0: local Python helper server (no CORS / WAF limits) ────────
  // Use same-origin when the page is served by the helper. This avoids issuing
  // duplicate localhost + 127.0.0.1 requests for the same lookup key.
  const localSpecUrls = location.protocol.startsWith('http')
    ? [`/spec?sn=${encodeURIComponent(snU)}`]
    : [`http://localhost:9527/spec?sn=${encodeURIComponent(snU)}`];
  for (const localUrl of localSpecUrls) {
    try {
      const localR = await fetch(
        localUrl,
        { signal: AbortSignal.timeout(20000) }
      );
      if (localR.ok) {
        const d = await localR.json();
        if (d && (d.processor || d.memory || d.driveType || d.gpu || d.productName || d.mtm || d.productId)) {
          const res = {};
          if (d.processor) { res.processor = d.processor; res.procQty  = d.procQty  || 1; }
          if (d.memory)    { res.memory    = d.memory;    res.memQty   = d.memQty   || 1; }
          if (d.driveType) { res.driveType = d.driveType; res.driveSize= d.driveSize||''; res.driveQty = d.driveQty || 1; }
          if (d.gpu)       { res.gpu       = d.gpu;       res.gpuQty   = d.gpuQty   || 1; }
          if (d.year)        res.year       = d.year;
          if (d.productId)   res._productId = d.productId;
          if (d.mtm)         res._mtm       = d.mtm;
          if (d.productName) res._productName = d.productName;
          res._metadataOnly = !(res.processor || res.memory || res.driveType || res.gpu);
          if (Object.keys(res).length > 0) {
            console.log('[SpecServer] OK via', localUrl, res);
            return res;
          }
        }
      } else {
        console.warn('[SpecServer] HTTP', localR.status, 'from', localUrl);
      }
    } catch(e) {
      console.warn('[SpecServer] fetch failed (', localUrl, '):', e.message);
    }
  }

  // ── Browser-side fallback: CORS proxy chain ───────────────────────────────
  const PROXIES = [
    function(u){ return u; },
    function(u){ return "https://corsproxy.io/?url="      + encodeURIComponent(u); },
    function(u){ return "https://api.allorigins.win/raw?url=" + encodeURIComponent(u); },
    function(u){ return "https://api.codetabs.com/v1/proxy?quest=" + encodeURIComponent(u); }
  ];

  // Helper: try a URL through all proxies; return response text or null
  async function tryFetch(url, accept, timeoutMs) {
    for (var pi = 0; pi < PROXIES.length; pi++) {
      try {
        var r = await fetch(PROXIES[pi](url), {
          headers: { "Accept": accept },
          signal: AbortSignal.timeout(timeoutMs || 12000)
        });
        if (!r.ok) continue;
        var text = await r.text();
        if (text && text.length > 20) return text;
      } catch(e) { console.warn("tryFetch:", e.message); }
    }
    return null;
  }

  // ── Step 1: Resolve SN → product metadata ────────────────────────────────
  var prodUrl = "https://pcsupport.lenovo.com/api/v4/mse/getproducts?productId=" + snU;
  var prodJson = await tryFetch(prodUrl, "application/json", 10000);
  if (!prodJson) return null;
  var products;
  try { products = JSON.parse(prodJson); } catch(e) { return null; }
  if (!Array.isArray(products) || !products[0] || !products[0].Id) return null;

  var productId   = products[0].Id.toLowerCase();
  var productName = products[0].Name || "";
  // Some responses include the full page URL (with MTM + SN) — use it if present
  var productUrl  = products[0].Url || products[0].ProductUrl || "";
  var mtm         = products[0].MTM || products[0].MachineType || "";

  // Store MTM on the calling row (best-effort, caught by caller via _mtm)
  var result = null;

  // ── Step 2a: Try JSON spec API endpoints (no WAF risk) ───────────────────
  // Lenovo's API occasionally exposes a dedicated spec endpoint
  var specApiCandidates = [
    "https://pcsupport.lenovo.com/api/v4/mse/getproductspec?productId=" + snU,
    "https://pcsupport.lenovo.com/api/v4/mse/getproductspec?productId=" + encodeURIComponent(productId),
  ];
  if (mtm) specApiCandidates.push(
    "https://pcsupport.lenovo.com/api/v4/mse/getproductspec?productId=" + encodeURIComponent(mtm)
  );

  for (var si = 0; si < specApiCandidates.length; si++) {
    var specJson = await tryFetch(specApiCandidates[si], "application/json", 10000);
    if (!specJson) continue;
    try {
      var ds = JSON.parse(specJson);
      // Possible shapes: {Specification:"..."} | {spec:{...}} | [{Processor:...}]
      var specRaw = ds.Specification || ds.specification
                 || (Array.isArray(ds) && ds[0] && ds[0].Specification)
                 || null;
      if (specRaw) {
        result = _parseSpecPayload(specRaw, productName);
        if (result) { result._productId = productId; result._mtm = mtm; result._productName = productName; result._metadataOnly = false; return result; }
      }
    } catch(e) { /* not JSON spec shape */ }
  }

  // ── Step 2b: Fetch product HTML page, try multiple URL patterns ──────────
  // Priority order of URLs to try (more specific URLs are less likely to hit
  // the generic WAF rule that blocks /{productId} alone):
  var htmlCandidates = [];

  // Use the URL returned by the API if present (includes full path + MTM + SN)
  if (productUrl) {
    var base = "https://pcsupport.lenovo.com";
    htmlCandidates.push(productUrl.startsWith("http") ? productUrl : base + productUrl);
  }
  // Full path with SN appended (mirrors what warranty-lookup redirects to)
  htmlCandidates.push(
    "https://pcsupport.lenovo.com/de/en/products/" + productId
    + (mtm ? "/" + mtm.toLowerCase() : "")
    + "/" + snU.toLowerCase()
  );
  // Short path (current fallback)
  htmlCandidates.push("https://pcsupport.lenovo.com/de/en/products/" + productId);

  for (var hi = 0; hi < htmlCandidates.length; hi++) {
    var html = await tryFetch(htmlCandidates[hi], "text/html", 22000);
    if (!html) continue;
    result = _parseSpecFromHtml(html, productName);
    if (result) { result._productId = productId; result._mtm = mtm; result._productName = productName; result._metadataOnly = false; return result; }
  }

  if (productName || mtm || productId) {
    return {_productId: productId, _mtm: mtm, _productName: productName, _metadataOnly: true};
  }
  return null;
}

// Extract spec table from Lenovo product page HTML
function _parseSpecFromHtml(html, productName) {
  // Primary: window.config.product.Specification (JSON-escaped HTML table)
  var m = html.match(/"Specification"\s*:\s*"((?:[^"\\]|\\.)*)"/);
  if (m) {
    var raw = m[1]
      .split("\\n").join("\n").split("\\t").join("\t")
      .split("\\\"").join('"').split("\\\\").join("\\");
    var t = _htmlTableToObj(raw);
    if (Object.keys(t).length) return buildSpecsFromTable(t, productName);
  }
  // Fallback: bare <table> rows in the page
  var t2 = _htmlTableToObj(html);
  if (Object.keys(t2).length) return buildSpecsFromTable(t2, productName);
  return null;
}

// Parse a spec payload that may be an HTML string or a JSON object
function _parseSpecPayload(data, productName) {
  if (typeof data === "string") {
    var t = _htmlTableToObj(data);
    return Object.keys(t).length ? buildSpecsFromTable(t, productName) : null;
  }
  if (typeof data === "object" && data !== null) {
    var t2 = {};
    for (var k in data) t2[k.toLowerCase()] = String(data[k]);
    return buildSpecsFromTable(t2, productName);
  }
  return null;
}

// Convert <td>Label</td><td>Value</td> pairs → {label: value} map
function _htmlTableToObj(html) {
  var table = {};
  var re = /<td[^>]*>([^<]+)<\/td>\s*<td[^>]*>([^<]*)<\/td>/gi;
  var rm;
  while ((rm = re.exec(html)) !== null) {
    table[rm[1].trim().toLowerCase()] = rm[2].trim();
  }
  return table;
}

function buildSpecsFromTable(table, productName) {
  const specs = {};

  // Processor
  const proc = table["processor"]||table["cpu"]||"";
  if(proc && proc!=="1x "&&proc!=="1x") {
    specs.processor = proc;
    const m = proc.match(/^(\d+)x/i); specs.procQty = m?+m[1]:1;
  }

  // Memory
  const mem = table["memory"]||table["ram"]||"";
  if(mem && mem!=="1x "&&mem!=="1x") {
    specs.memory = mem;
    const m = mem.match(/^(\d+)x/i); specs.memQty = m?+m[1]:1;
  }

  // Hard Drive
  const drv = table["hard drive"]||table["storage"]||table["ssd"]||table["hdd"]||"";
  if(drv) parseDrive(drv, specs);

  // GPU / Graphics
  const gpu = table["graphics"]||table["gpu"]||"";
  if(gpu && gpu!=="1x "&&gpu!=="1x") {
    specs.gpu = gpu;
    const m = gpu.match(/^(\d+)x/i); specs.gpuQty = m?+m[1]:1;
  }

  // Model year — try to detect from product name or OS
  const osVal = table["operating system"]||"";
  const yearM = productName.match(/Gen\s*(\d+)/i)||productName.match(/20(\d{2})/);
  if(yearM) specs.year = yearM[0].includes("Gen") ? String(2019+parseInt(yearM[1])) : "20"+yearM[1];

  return Object.keys(specs).length>0 ? specs : null;
}

function parseDrive(v,specs){
  if(!v) return;
  if(v.includes("NVMe")||v.includes("PCIe"))             specs.driveType="SSD PCIe NVMe";
  else if(v.includes("SSD")&&v.includes("SATA"))         specs.driveType="SSD SATA";
  else if(v.includes("SSD"))                             specs.driveType="SSD";
  else if(v.includes("HDD")||/\d+RPM/.test(v))          specs.driveType="HDD";
  else                                                   specs.driveType="SSD";
  const sm = v.match(/(\d+)\s*(GB|TB)/i);
  if(sm) specs.driveSize=sm[1]+sm[2].toUpperCase();
  const qm = v.match(/^(\d+)x/i);
  specs.driveQty = qm?+qm[1]:1;
}

function generateARS(){
  const btn=document.getElementById("genBtn");
  const fab=document.getElementById("fabGen");
  btn.disabled=true; fab.disabled=true;
  btn.innerHTML='<span class="spinner"></span> Generating...';
  fab.innerHTML='<span class="spinner"></span> Generating...';
  doGenerate()
    .catch(e=>{alert("Error: "+e.message);console.error(e);})
    .finally(()=>{btn.disabled=false;fab.disabled=false;btn.innerHTML="&#11015; Generate Pick-up Request";fab.innerHTML="&#11015; Generate Pick-up Request";});
}

/* ──────────────────────────────────────────────────────
   JSZip-based XLSX generation (preserves all styles)
   ────────────────────────────────────────────────────── */

// XML-escape a string value
function x$(s){ return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

// Convert YYYY-MM-DD → Excel serial number
function dateToSerial(dateStr){
  const [y,m,d]=dateStr.split('-').map(Number);
  return Math.floor(Date.UTC(y,m-1,d)/86400000)+25569;
}

// Replace cell content → inlineStr, preserving s= style index
// Always overwrites — clears template placeholder when value is empty
function setStr(xml,ref,value){
  const v=(value===undefined||value===null)?'':x$(String(value));
  return xml.replace(
    new RegExp(`<c r="${ref}" s="(\\d+)"(?:\\s+t="[^"]*")?>(?:[\\s\\S]*?)<\\/c>`,'g'),
    v ? `<c r="${ref}" s="$1" t="inlineStr"><is><t>${v}</t></is></c>`
      : `<c r="${ref}" s="$1" t="n"></c>`
  );
}

// Replace cell content → numeric, preserving s= style index
// Always overwrites — clears template placeholder when value is empty
function setNum(xml,ref,value){
  return xml.replace(
    new RegExp(`<c r="${ref}" s="(\\d+)"(?:\\s+t="[^"]*")?>(?:[\\s\\S]*?)<\\/c>`,'g'),
    (value!==null&&value!==undefined&&value!==''&&value!==0||value===0)
      ? `<c r="${ref}" s="$1"><v>${value}</v></c>`
      : `<c r="${ref}" s="$1" t="n"></c>`
  );
}

// Build a new product row XML (rows 4+)
function makeProductRow(rn,d){
  const S=(col,val,s)=>val
    ?`<c r="${col}${rn}" s="${s}" t="inlineStr"><is><t>${x$(val)}</t></is></c>`
    :`<c r="${col}${rn}" s="${s}" t="n"></c>`;
  const N=(col,val,s)=>(val!==''&&val!==undefined&&val!==null)
    ?`<c r="${col}${rn}" s="${s}"><v>${val}</v></c>`
    :`<c r="${col}${rn}" s="${s}" t="n"></c>`;
  return `<row r="${rn}" ht="18" customHeight="1">`+
    S('A',d.pt,104)+S('B',d.mfr,5)+S('C',d.model,5)+
    N('D',d.qty,5)+S('E',d.grade,5)+N('F',d.year,5)+
    S('G',d.proc,105)+N('H',d.pqty,5)+
    S('I',d.mem,105)+N('J',d.mqty,5)+
    S('K',d.dtype,106)+S('L',d.dsize,106)+N('M',d.dqty,106)+
    S('N',d.gpu,106)+N('O',d.gqty,107)+
    `<c r="R${rn}" s="3" t="n"></c>`+
    `</row>`;
}

function getRowData(tr){
  const v=cls=>(tr.querySelector(cls)||{}).value||'';
  const n=cls=>{const x=parseInt(v(cls));return isNaN(x)?'':x;};
  return{
    pt:v('.f-pt'),mfr:v('.f-mfr'),model:v('.f-model'),
    qty:n('.f-qty')||1,grade:v('.f-grade'),year:v('.f-year'),
    proc:v('.f-proc'),pqty:n('.f-pqty'),
    mem:v('.f-mem'),mqty:n('.f-mqty'),
    dtype:v('.f-dtype'),dsize:v('.f-dsize'),dqty:n('.f-dqty'),
    gpu:v('.f-gpu'),gqty:n('.f-gqty'),
  };
}

function modelMergeKey(tr) {
  const mtm = (tr.dataset.mtm || '').trim().toLowerCase();
  if (mtm) return 'mtm:' + mtm;
  const productName = (tr.dataset.productName || '').trim().toLowerCase();
  if (productName) return 'name:' + productName;
  return '';
}

function mergeDuplicateProductRow(sourceTr) {
  const key = modelMergeKey(sourceTr);
  if (!key) return sourceTr;

  const targetTr = [...document.querySelectorAll('#ptbody tr')]
    .find(tr => tr !== sourceTr && modelMergeKey(tr) === key);
  if (!targetTr) return sourceTr;

  let sourceSns = [], targetSns = [];
  try { sourceSns = JSON.parse(sourceTr.dataset.sns || '[]'); } catch(e) { sourceSns = []; }
  try { targetSns = JSON.parse(targetTr.dataset.sns || '[]'); } catch(e) { targetSns = []; }
  const mergedSns = [...targetSns, ...sourceSns].filter((sn, i, arr) => sn && arr.indexOf(sn) === i);
  targetTr.dataset.sns = JSON.stringify(mergedSns);
  targetTr.dataset.mtm = targetTr.dataset.mtm || sourceTr.dataset.mtm || '';
  targetTr.dataset.productName = targetTr.dataset.productName || sourceTr.dataset.productName || '';
  targetTr.dataset.productId = targetTr.dataset.productId || sourceTr.dataset.productId || '';

  const targetQty = targetTr.querySelector('.f-qty');
  if (targetQty) targetQty.value = mergedSns.length || Number(targetQty.value || 0) + Number((sourceTr.querySelector('.f-qty') || {}).value || 0);

  const fields = ['.f-year','.f-proc','.f-pqty','.f-mem','.f-mqty','.f-dtype','.f-dsize','.f-dqty','.f-gpu','.f-gqty'];
  fields.forEach(cls => {
    const target = targetTr.querySelector(cls);
    const source = sourceTr.querySelector(cls);
    if (target && source && !target.value && source.value) target.value = source.value;
  });

  const targetBadge = document.getElementById('bs-' + targetTr.dataset.idx);
  const sourceBadge = document.getElementById('bs-' + sourceTr.dataset.idx);
  if (targetBadge && sourceBadge && !targetBadge.classList.contains('b-ok') && !targetBadge.classList.contains('b-cache')) {
    targetBadge.className = sourceBadge.className;
    targetBadge.innerHTML = sourceBadge.innerHTML;
    targetBadge.title = sourceBadge.title || targetBadge.title;
  }

  sourceTr.remove();
  refreshProductRowNumbers();
  refreshSerialNumberGroups();
  return targetTr;
}

function refreshProductRowNumbers() {
  document.querySelectorAll('#ptbody tr').forEach((tr, i) => {
    const seq = tr.querySelector('.col-seq');
    if (seq) seq.textContent = i + 1;
  });
}

let _serialRefreshTimer = null;
function scheduleSerialNumberRefresh() {
  clearTimeout(_serialRefreshTimer);
  _serialRefreshTimer = setTimeout(refreshSerialNumberGroups, 80);
}

function removeProductRow(btn) {
  const tr = btn && btn.closest ? btn.closest('tr') : null;
  if (!tr) return;
  const model = ((tr.querySelector('.f-model') || {}).value || '').trim() || 'this product row';
  let sns = [];
  try { sns = JSON.parse(tr.dataset.sns || '[]'); } catch(e) { sns = []; }
  const ok = confirm(`Delete ${model}?\n\nThis will also remove ${sns.length} serial number${sns.length === 1 ? '' : 's'} from the Serial Numbers section.`);
  if (!ok) return;
  tr.remove();
  refreshProductRowNumbers();
  refreshSerialNumberGroups();
}

function buildSnRowsFromProductRows(){
  const seen = new Set();
  const rows = [];
  document.querySelectorAll('#ptbody tr').forEach(tr => {
    const model = ((tr.querySelector('.f-model') || {}).value || '').trim();
    const mtm = (tr.dataset.mtm || '').trim();
    const modelPart = [model, mtm]
      .filter(Boolean)
      .filter((v, i, arr) => arr.findIndex(x => String(x).toLowerCase() === String(v).toLowerCase()) === i)
      .join(' ');
    let sns = [];
    try { sns = JSON.parse(tr.dataset.sns || '[]'); } catch(e) { sns = []; }
    sns.forEach(sn => {
      if (!sn || seen.has(sn)) return;
      seen.add(sn);
      rows.push({ model: modelPart || 'Pending Lenovo lookup', sn });
    });
  });
  return rows;
}

async function doGenerate(){
  const bytes=b64ToArr(TMPL_B64);
  const zip=await JSZip.loadAsync(bytes);

  // ── Overview (sheet1.xml) ──
  let ov=await zip.file('xl/worksheets/sheet1.xml').async('string');
  ov=setStr(ov,'D7',document.getElementById('f_account').value);
  ov=setStr(ov,'D8',document.getElementById('f_addr').value);
  ov=setStr(ov,'D9',document.getElementById('f_country').value);
  const dv=document.getElementById('f_date').value;
  if(dv) ov=setNum(ov,'D10',dateToSerial(dv));
  ov=setStr(ov,'D11',document.getElementById('f_currency').value);
  ov=setStr(ov,'D12',document.getElementById('f_logistics').value);
  ov=setStr(ov,'D13',document.getElementById('f_datasec').value);
  ov=setStr(ov,'D14',document.getElementById('f_ss1').value);
  ov=setStr(ov,'D15',document.getElementById('f_ss2').value);
  ov=setStr(ov,'D16',document.getElementById('f_comments').value);
  zip.file('xl/worksheets/sheet1.xml',ov);

  // ── Product Details (sheet2.xml) ──
  const ptRows=Array.from(document.querySelectorAll('#ptbody tr'));
  if(ptRows.length>0){
    let pd=await zip.file('xl/worksheets/sheet2.xml').async('string');
    // Row 3: update the existing template row in-place
    const d0=getRowData(ptRows[0]);
    pd=setStr(pd,'A3',d0.pt);   pd=setStr(pd,'B3',d0.mfr);
    pd=setStr(pd,'C3',d0.model);pd=setNum(pd,'D3',d0.qty||1);
    pd=setStr(pd,'E3',d0.grade);pd=setNum(pd,'F3',d0.year);
    pd=setStr(pd,'G3',d0.proc); pd=setNum(pd,'H3',d0.pqty);
    pd=setStr(pd,'I3',d0.mem);  pd=setNum(pd,'J3',d0.mqty);
    pd=setStr(pd,'K3',d0.dtype);pd=setStr(pd,'L3',d0.dsize);
    pd=setNum(pd,'M3',d0.dqty);
    pd=setStr(pd,'N3',d0.gpu);  pd=setNum(pd,'O3',d0.gqty);
    // Rows 4+: append new row XML
    if(ptRows.length>1){
      const extra=ptRows.slice(1).map((tr,i)=>makeProductRow(i+4,getRowData(tr))).join('');
      pd=pd.replace('</sheetData>',extra+'</sheetData>');
      pd=pd.replace(/(<dimension ref=")[^"]*(")/,`$1A1:R${ptRows.length+2}$2`);
    }
    zip.file('xl/worksheets/sheet2.xml',pd);
  }

  // ── SN (sheet3.xml) ──
  const snRowsForExport = buildSnRowsFromProductRows();
  if(snRowsForExport.length>0){
    let sn=await zip.file('xl/worksheets/sheet3.xml').async('string');
    const C=(col,r,val,s)=>`<c r="${col}${r}" s="${s}" t="inlineStr"><is><t>${x$(val)}</t></is></c>`;
    const rowsXml = [
      `<row r="1">${C('A',1,'Model / Part Number',111)}${C('B',1,'Serial Number',111)}</row>`,
      ...snRowsForExport.map((item,i)=>{
        const r=i+2;
        return `<row r="${r}">${C('A',r,item.model,112)}${C('B',r,item.sn,112)}</row>`;
      })
    ].join('');
    sn=sn.replace(/<sheetData>[\s\S]*<\/sheetData>/,`<sheetData>${rowsXml}</sheetData>`);
    sn=sn.replace(/(<dimension ref=")[^"]*(")/,`$1A1:B${snRowsForExport.length+1}$2`);
    zip.file('xl/worksheets/sheet3.xml',sn);
  }

  // ── Pack & download ──
  const acct=(document.getElementById('f_account').value||'ARS').replace(/[^\w\-]/g,'_').slice(0,30);
  const today=new Date().toISOString().slice(0,10);
  const outName=`ARS_Template_${acct}_${today}.xlsx`;
  const el=document.getElementById('genNoteFilename');
  if(el) el.textContent=outName;
  const blob=await zip.generateAsync({
    type:'blob',
    mimeType:'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
    compression:'DEFLATE',compressionOptions:{level:6}
  });
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url;a.download=outName;a.click();
  setTimeout(()=>URL.revokeObjectURL(url),1000);
}

function b64ToArr(b64){
  const bin=atob(b64);
  const arr=new Uint8Array(bin.length);
  for(let i=0;i<bin.length;i++) arr[i]=bin.charCodeAt(i);
  return arr.buffer;
}


