// SCENARIO 2 – Recovery Status Analyzer
// ════════════════════════════════════════════════════════
let puFileList = [];  // pick-up request File objects
let crFileList = [];  // collection report File objects
let analysisRows = []; // final merged dataset
let puParseInfo = [];
let crParseInfo = [];

// ── Tab switch ──────────────────────────────────────────
function switchTab(id, btn) {
  document.querySelectorAll('.tab-pane').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
  document.getElementById(id).classList.add('active');
  btn.classList.add('active');
}

// Keep FAB visibility in sync when user switches tabs
function updateFabForTab() {
  try {
    const fab = document.getElementById('fabGen');
    if (!fab) return;
    const activePane = document.querySelector('.tab-pane.active');
    if (!activePane || activePane.id !== 't1') {
      fab.classList.remove('visible');
      return;
    }
    // on t1, show only if there are product rows
    const hasRows = document.querySelectorAll('#ptbody tr').length > 0;
    if (hasRows) fab.classList.add('visible'); else fab.classList.remove('visible');
  } catch (e) { console.warn('updateFabForTab error', e); }
}

// Ensure switchTab triggers FAB update
const _origSwitchTab = switchTab;
switchTab = function(id, btn) {
  _origSwitchTab(id, btn);
  updateFabForTab();
};

// ── Drag helpers ────────────────────────────────────────
function evDrag(e, dropId) { e.preventDefault(); document.getElementById(dropId).classList.add('drag'); }
function evLeave(dropId)    { document.getElementById(dropId).classList.remove('drag'); }
function evDrop(e, inputId, dropId) {
  e.preventDefault();
  document.getElementById(dropId).classList.remove('drag');
  const fi = document.getElementById(inputId);
  // Synthetic FileList via DataTransfer
  const dt = new DataTransfer();
  [...(fi.files||[])].forEach(f => dt.items.add(f));
  [...e.dataTransfer.files].filter(f=>f.name.endsWith('.xlsx')).forEach(f => dt.items.add(f));
  fi.files = dt.files;
  fi.dispatchEvent(new Event('change'));
}

// ── File input handlers ─────────────────────────────────
document.getElementById('puFiles').addEventListener('change', async function() {
  mergeFiles(this, puFileList, 'puChips');
  await refreshFileParseStatus('pu');
  checkAnalyzeReady();
});
document.getElementById('crFiles').addEventListener('change', async function() {
  mergeFiles(this, crFileList, 'crChips');
  await refreshFileParseStatus('cr');
  checkAnalyzeReady();
});

function mergeFiles(input, arr, chipsId) {
  [...input.files].forEach(f => {
    if (!arr.find(x => x.name === f.name && x.size === f.size)) arr.push(f);
  });
  renderChips(arr, chipsId, arr === puFileList ? 'puFiles' : 'crFiles');
}

function renderChips(arr, chipsId, inputId) {
  const el = document.getElementById(chipsId);
  el.innerHTML = arr.map((f, i) =>
    `<span class="chip">&#128196; ${esc(f.name)}
      <span class="rm" onclick="removeFile(${i},'${inputId}','${chipsId}')">&#10005;</span>
    </span>`
  ).join('');
}

function removeFile(idx, inputId, chipsId) {
  const arr = inputId === 'puFiles' ? puFileList : crFileList;
  arr.splice(idx, 1);
  renderChips(arr, chipsId, inputId);
  refreshFileParseStatus(inputId === 'puFiles' ? 'pu' : 'cr');
  checkAnalyzeReady();
}

function checkAnalyzeReady() {
  const show = puFileList.length > 0 || crFileList.length > 0;
  document.getElementById('analyzeCard').style.display = show ? '' : 'none';
  const btn = document.getElementById('analyzeBtn');
  const hint = document.getElementById('analyzeHint');
  if (!btn || !hint) return;
  const ready = puFileList.length > 0 && crFileList.length > 0;
  btn.disabled = !ready;
  if (!ready) {
    hint.textContent = puFileList.length
      ? 'Upload at least one Collection Report file to compare recovered devices.'
      : 'Upload at least one Pick-up Request file to define the requested baseline.';
  } else {
    hint.textContent = 'Pick-up Request serial numbers are the requested baseline. Collection Report serial numbers confirm recovered devices.';
  }
}

function renderParseStatus(kind, infos) {
  const el = document.getElementById(kind === 'pu' ? 'puStatus' : 'crStatus');
  if (!el) return;
  if (!infos.length) {
    el.className = 'upload2-status';
    el.innerHTML = '';
    return;
  }
  const safeInfos = infos.map(info => Array.isArray(info) ? {file:'', count:info.length, rows:info, method:''} : info);
  const unique = new Set(safeInfos.flatMap(info => (info.rows || []).map(r => r.sn))).size;
  const hasSn = unique > 0;
  el.className = 'upload2-status ' + (hasSn ? 'ok' : 'warn');
  const methods = [...new Set(safeInfos.map(info => info.method).filter(Boolean))].join(', ') || 'No SN detected';
  el.innerHTML = `
    <div class="status-line"><span class="status-main">${safeInfos.length} file${safeInfos.length !== 1 ? 's' : ''} loaded</span><span>${unique} unique SN${unique !== 1 ? 's' : ''}</span></div>
    <div class="status-line"><span>Detection</span><span>${esc(methods)}</span></div>
  `;
}

async function refreshFileParseStatus(kind) {
  const files = kind === 'pu' ? puFileList : crFileList;
  const infos = await Promise.all(files.map(file => parseXlsxForSN(file, {withMeta:true})));
  if (kind === 'pu') puParseInfo = infos; else crParseInfo = infos;
  renderParseStatus(kind, infos);
}

function emptyParseResult(file, method) {
  return {file: file ? file.name : '', count: 0, rows: [], method: method || 'No SN detected'};
}

async function getParseInfos(kind) {
  const files = kind === 'pu' ? puFileList : crFileList;
  let infos = kind === 'pu' ? puParseInfo : crParseInfo;
  if (infos.length !== files.length) {
    infos = await Promise.all(files.map(file => parseXlsxForSN(file, {withMeta:true})));
    if (kind === 'pu') puParseInfo = infos; else crParseInfo = infos;
    renderParseStatus(kind, infos);
  }
  return infos;
}

function uniqueSnCount(infos) {
  return new Set(infos.flatMap(info => (info.rows || []).map(r => r.sn))).size;
}

// ── Parse xlsx → array of {sn, model, account, file} ───
function looksLikeSerialNumberValue(value) {
  const sn = String(value || '').trim().toUpperCase();
  if (!sn) return false;
  if (/^(SERIAL|S\/N|SN|MANUF\.?\s*SN)$/i.test(sn)) return false;
  return /^[A-Z0-9]{6,18}$/.test(sn) && /\d/.test(sn) && /[A-Z]/.test(sn);
}

async function parseXlsxForSN(file, options) {
  options = options || {};
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.onload = e => {
      try {
        var XLSXLib2 = _XLSX || window.XLSX;
        if (!XLSXLib2) { resolve(options.withMeta ? emptyParseResult(file, 'XLSX reader unavailable') : []); return; }
        const wb = XLSXLib2.read(new Uint8Array(e.target.result), {type:'array'});
        const allRows = [];
        let method = '';

        // Sort sheets: SN-dedicated sheets first
        const sheetOrder = [...wb.SheetNames].sort((a,b) => {
          const ap = /^sn$|serial/i.test(a.trim()) ? 0 : 1;
          const bp = /^sn$|serial/i.test(b.trim()) ? 0 : 1;
          return ap - bp;
        });

        sheetOrder.forEach(sname => {
          const ws = wb.Sheets[sname];
          const data = XLSXLib2.utils.sheet_to_json(ws, {defval:'', raw:false});
          if (!data.length) return;

          const origKeys = Object.keys(data[0]);
          function findKey(testFn) {
            return origKeys.find(k => testFn(k.trim().toLowerCase()));
          }

          // Skip known template/metadata sheets that never contain device SNs
          const SKIP_SHEETS = ['definitions','read me','product type and grade',
            'product type value','country code','overview'];
          if (SKIP_SHEETS.includes(sname.trim().toLowerCase())) return;

          // Match all SN column name variants
          // Guard: real SN column names are short (<60 chars); long descriptive
          // names like "Small Serialized Assets (…not included…)" must not match.
          const snKey = findKey(kt =>
            kt.length < 60 && (
              /^s[/\\]n$/.test(kt)                    ||  // "S/N"
              /^sn$/.test(kt)                           ||  // "SN"
              /^serial[\s#_\-]*(num|no|number)\b/.test(kt) ||  // "Serial Number/No"
              /^serial$/.test(kt)                       ||  // exactly "serial"
              /^manuf[^a-z]*sn$/.test(kt)               ||  // "Manuf. SN"
              /^manuf[^a-z]*s\/n$/.test(kt)            ||  // "Manuf. S/N"
              /^mfr[^a-z]*sn$/.test(kt)                 ||  // "Mfr SN"
              /^asset[^a-z]*sn$/.test(kt)                   // "Asset SN"
            )
          );

          if (!snKey) return;
          method = method || `${sname}: ${snKey}`;

          // Model column
          const modKey = findKey(kt =>
            /^model(\s*name)?$/.test(kt) ||
            /material.?desc/.test(kt)    ||
            /^description$/.test(kt)
          );

          // Account / Brand
          const accKey = findKey(kt =>
            /account|company|customer/.test(kt) ||
            /^make$|^brand$|make.*brand|brand.*name/.test(kt)
          );

          data.forEach(row => {
            const sn = String(row[snKey] || '').trim().toUpperCase();
            if (!sn || /^(serial|s\/n|sn|manuf\.?\s*sn)/i.test(sn)) return;
            allRows.push({
              sn,
              model:   modKey ? String(row[modKey] || '').trim() : '',
              account: accKey ? String(row[accKey] || '').trim() : '',
              file:    file.name
            });
          });
        });

        // Fallback for files/sheets that are just raw SN lists without a
        // header row, e.g. columns A/B contain PW05JAMX, PW05JD22, ...
        if (!allRows.length) {
          sheetOrder.forEach(sname => {
            const ws = wb.Sheets[sname];
            const rows = XLSXLib2.utils.sheet_to_json(ws, {header:1, defval:'', raw:false});
            if (!rows.length) return;

            const flat = [];
            rows.forEach(row => row.forEach(value => {
              const sn = String(value || '').trim().toUpperCase();
              if (looksLikeSerialNumberValue(sn)) flat.push(sn);
            }));

            const unique = flat.filter((sn, i, arr) => arr.indexOf(sn) === i);
            if (unique.length < 3) return;
            method = method || `${sname}: raw SN list`;
            unique.forEach(sn => allRows.push({
              sn,
              model: '',
              account: '',
              file: file.name
            }));
          });
        }

        const result = options.withMeta
          ? {file: file.name, count: allRows.length, rows: allRows, method: method || 'No SN detected'}
          : allRows;
        resolve(result);
      } catch(err) {
        console.warn('Parse error', file.name, err);
        resolve(options.withMeta ? emptyParseResult(file, 'Parse error') : []);
      }
    };
    reader.readAsArrayBuffer(file);
  });
}

// ── SN normalization: strip a single leading letter prefix if present ──────
// Some systems (e.g. ALM/pick-up) prepend 'S' to standard Lenovo SNs.
// We build a lookup map with BOTH the raw SN and the stripped version so
// that "SPW016SZT" (pick-up) correctly matches "PW016SZT" (collection report).
function buildConfirmedMap(crRows) {
  const map = {};  // normalized-sn → collection-file-name
  crRows.forEach(r => {
    const sn = r.sn;
    map[sn] = map[sn] || r.file;          // store as-is
    // Also pre-pad with 'S' so pick-up SNs like "SPW016SZT" can find "PW016SZT"
    const withS = 'S' + sn;
    map[withS] = map[withS] || r.file;
    // And strip leading letter in case the CR SN is the one with prefix
    if (/^[A-Z][A-Z0-9]{5,}$/.test(sn)) {
      const stripped = sn.slice(1);
      map[stripped] = map[stripped] || r.file;
    }
  });
  return map;
}

// ── Run analysis ────────────────────────────────────────
async function runAnalysis() {
  const btn = document.getElementById('analyzeBtn');
  btn.disabled = true;
  btn.innerHTML = '<span class="spinner"></span> Analyzing…';

  const puInfos = await getParseInfos('pu');
  const crInfos = await getParseInfos('cr');
  const puRows = puInfos.flatMap(info => info.rows || []);
  const crRows = crInfos.flatMap(info => info.rows || []);

  if (!puRows.length) {
    analysisRows = [];
    document.getElementById('resultsCard').classList.add('hidden');
    const summaryEl = document.getElementById('analysisSummary');
    if (summaryEl) summaryEl.innerHTML = '';
    alert('No serial numbers found in the Pick-up Request file. Please check the SN sheet or upload a Pick-up Request file with serial number details.');
    btn.disabled = false;
    btn.innerHTML = '&#128202; Re-Analyze';
    return;
  }

  const confirmedMap = buildConfirmedMap(crRows);

  // De-duplicate SNs, preserve all source files
  const seen = {};
  puRows.forEach(r => {
    if (!seen[r.sn]) seen[r.sn] = {...r, sources: [r.file]};
    else if (!seen[r.sn].sources.includes(r.file)) seen[r.sn].sources.push(r.file);
  });

  // Total Devices = unique SNs from pick-up files only
  analysisRows = Object.values(seen).map(r => ({
    sn:          r.sn,
    model:       r.model,
    account:     r.account,
    sourceFile:  r.sources.join(', '),
    recovered:   !!confirmedMap[r.sn],
    confirmedIn: confirmedMap[r.sn] || ''
  }));

  renderStats();
  renderAnalysisSummary(puInfos, crInfos);
  renderTable();
  const resultsCard = document.getElementById('resultsCard');
  resultsCard.classList.remove('hidden');
  setTimeout(() => resultsCard.scrollIntoView({behavior:'smooth', block:'start'}), 80);
  btn.disabled = false;
  btn.innerHTML = '&#128202; Re-Analyze';
}

function renderAnalysisSummary(puInfos, crInfos) {
  const el = document.getElementById('analysisSummary');
  if (!el) return;
  const puUnique = uniqueSnCount(puInfos);
  const crUnique = uniqueSnCount(crInfos);
  const puMethods = [...new Set(puInfos.map(info => info.method).filter(Boolean))].join(', ') || 'No SN detected';
  const crMethods = [...new Set(crInfos.map(info => info.method).filter(Boolean))].join(', ') || 'No SN detected';
  el.innerHTML = `
    <span class="analysis-pill">Pick-up: ${puUnique} unique SNs</span>
    <span class="analysis-pill">Collection: ${crUnique} unique SNs</span>
    <span class="analysis-pill">PU detection: ${esc(puMethods)}</span>
    <span class="analysis-pill">CR detection: ${esc(crMethods)}</span>
    <span class="analysis-pill warn">Match rule: raw SN + S-prefix compatible</span>
  `;
}

// ── Stats ───────────────────────────────────────────────
function renderStats() {
  const total = analysisRows.length;
  const done  = analysisRows.filter(r => r.recovered).length;
  const pend  = total - done;
  const rate  = total ? Math.round(done/total*100) : 0;
  document.getElementById('statRow').innerHTML = `
    <div class="stat-card sc-total"><div class="num">${total}</div><div class="lbl">Total Devices Requested</div></div>
    <div class="stat-card sc-ok"><div class="num">${done}</div><div class="lbl">✅ Recovered</div></div>
    <div class="stat-card sc-pend"><div class="num">${pend}</div><div class="lbl">⚠️ Not Yet Recovered</div></div>
    <div class="stat-card sc-rate"><div class="num">${rate}%</div><div class="lbl">Recovery Rate</div></div>
  `;
}

// ── Table ───────────────────────────────────────────────
function renderTable() {
  const status = document.getElementById('filterStatus').value;
  const search = document.getElementById('filterSearch').value.toLowerCase();
  let rows = analysisRows;
  if (status === 'recovered') rows = rows.filter(r =>  r.recovered);
  if (status === 'pending')   rows = rows.filter(r => !r.recovered);
  if (search) rows = rows.filter(r =>
    r.sn.toLowerCase().includes(search) ||
    r.model.toLowerCase().includes(search) ||
    r.account.toLowerCase().includes(search)
  );

  const tbody = document.getElementById('resTbody');
  tbody.innerHTML = rows.map((r, i) => `
    <tr class="${r.recovered ? 'row-ok' : 'row-pend'}">
      <td class="res-sticky-idx">${i+1}</td>
      <td class="res-sticky-sn"><strong>${r.sn}</strong></td>
      <td>${esc(r.model || '—')}</td>
      <td>${esc(r.account || '—')}</td>
      <td class="file-cell" title="${esc(r.sourceFile)}">${esc(r.sourceFile)}</td>
      <td>${r.recovered
        ? '<span class="tag-ok">✅ Recovered</span>'
        : '<span class="tag-pend">⚠️ Pending</span>'}</td>
      <td class="file-cell" title="${esc(r.confirmedIn || '')}">${esc(r.confirmedIn || '—')}</td>
    </tr>`
  ).join('');
}

// ── Export results ──────────────────────────────────────
function exportResults() {
  if (!analysisRows.length) return;
  const status = document.getElementById('filterStatus').value;
  const search = document.getElementById('filterSearch').value.toLowerCase();
  let rows = analysisRows;
  if (status === 'recovered') rows = rows.filter(r =>  r.recovered);
  if (status === 'pending')   rows = rows.filter(r => !r.recovered);
  if (search) rows = rows.filter(r =>
    r.sn.toLowerCase().includes(search) ||
    r.model.toLowerCase().includes(search) ||
    r.account.toLowerCase().includes(search)
  );

  var XLSXLib = _XLSX || window.XLSX;
  const wb = XLSXLib.utils.book_new();

  // Summary sheet
  const total = analysisRows.length;
  const done  = analysisRows.filter(r => r.recovered).length;
  const sumData = [
    ['Recovery Status Summary'],
    [],
    ['Total Devices',         total],
    ['Recovered',             done],
    ['Not Yet Recovered',     total - done],
    ['Recovery Rate',         total ? (done/total*100).toFixed(1)+'%' : '0%'],
    [],
    ['Generated on', new Date().toLocaleDateString()]
  ];
  const wsSummary = XLSXLib.utils.aoa_to_sheet(sumData);
  XLSXLib.utils.book_append_sheet(wb, wsSummary, 'Summary');

  // Detail sheet
  const header = ['Serial Number','Model','Account','Source File (Pick-up Request)','Status','Confirmed In (Collection Report)'];
  const detail = [header, ...rows.map(r => [
    r.sn, r.model, r.account, r.sourceFile,
    r.recovered ? 'Recovered' : 'Not Yet Recovered',
    r.confirmedIn || ''
  ])];
  const wsDetail = XLSXLib.utils.aoa_to_sheet(detail);
  wsDetail['!cols'] = [22,30,28,40,22,40].map(w=>({wch:w}));
  XLSXLib.utils.book_append_sheet(wb, wsDetail, 'Recovery Details');

  const today = new Date().toISOString().slice(0,10);
  XLSXLib.writeFile(wb, `Recovery_Status_${today}.xlsx`);
}


// ── Spec paste modal ──────────────────────────────────────────────────────
var _specModalTarget = null;
var _specModalProductId = null;

function openSpecModal(idx) {
  _specModalTarget = idx;
  document.getElementById('specPasteArea').value = '';

  // Show model name + SNs in modal header
  var tr = document.querySelector('tr[data-idx="' + idx + '"]');
  var modelName = tr ? ((tr.querySelector('.f-model')||{}).value || '') : '';
  var sns = tr ? JSON.parse(tr.dataset.sns || '[]') : [];
  var snPreview = sns.slice(0,3).join(', ') + (sns.length > 3 ? ' …' : '');
  var titleEl = document.getElementById('specModalTitle');
  var snEl    = document.getElementById('specModalSN');
  if(titleEl) titleEl.textContent = modelName || 'Spec Lookup';
  if(snEl)    snEl.textContent    = snPreview ? 'SN: ' + snPreview : '';

  document.getElementById('specModalBg').style.display = 'flex';
  // Focus the textarea so user can paste immediately
  setTimeout(function(){ document.getElementById('specPasteArea').focus(); }, 200);
}

function closeSpecModal() {
  document.getElementById('specModalBg').style.display = 'none';
  _specModalTarget = null;
  _specModalProductId = null;
}

function openLenovoPage() {
  if (!_specModalTarget && _specModalTarget !== 0) return;
  var tr = document.querySelector('tr[data-idx="' + _specModalTarget + '"]');
  if (!tr) return;
  var sns = JSON.parse(tr.dataset.sns || '[]');
  var sn  = (sns[0] || '').toUpperCase();
  if (!sn) return;
  var pid = tr.dataset.productId || '';
  var mtm = tr.dataset.mtm || '';
  var url;
  if (pid) {
    // Full URL with MTM + SN mirrors what warranty-lookup navigates to
    url = 'https://pcsupport.lenovo.com/de/en/products/' + pid
        + (mtm ? '/' + mtm.toLowerCase() : '')
        + '/' + sn.toLowerCase();
  } else {
    // Not yet resolved — go to warranty lookup so user can confirm the device
    url = 'https://pcsupport.lenovo.com/de/en/warrantylookup#/' + sn;
  }
  window.open(url, '_blank');
}

function parseAndApplySpec() {
  var text = document.getElementById('specPasteArea').value.trim();
  if (!text) return;
  var tr = document.querySelector('tr[data-idx="' + _specModalTarget + '"]');
  if (!tr) { closeSpecModal(); return; }

  // Parse pasted spec text: alternating label/value lines, or table rows
  var table = {};
  var lines = text.split(/\n|\r/).map(function(l){return l.trim();}).filter(Boolean);
  for (var i = 0; i < lines.length - 1; i++) {
    var key = lines[i].toLowerCase().replace(/[^a-z ]/g,'').trim();
    var val = lines[i+1];
    // Skip if value looks like another label (e.g., all caps)
    if (!/^[A-Z][A-Z ]+$/.test(val)) {
      table[key] = val;
      i++; // skip value line
    }
  }

  var specs = buildSpecsFromTable(table, '');
  if (specs) {
    if(specs.processor) tr.querySelector('.f-proc').value = specs.processor;
    if(specs.procQty)   tr.querySelector('.f-pqty').value = specs.procQty;
    if(specs.memory)    tr.querySelector('.f-mem').value  = specs.memory;
    if(specs.memQty)    tr.querySelector('.f-mqty').value = specs.memQty;
    if(specs.driveType) tr.querySelector('.f-dtype').value= specs.driveType;
    if(specs.driveSize) tr.querySelector('.f-dsize').value= specs.driveSize;
    if(specs.driveQty)  tr.querySelector('.f-dqty').value = specs.driveQty;
    if(specs.gpu)       tr.querySelector('.f-gpu').value  = specs.gpu;
    if(specs.gpuQty)    tr.querySelector('.f-gqty').value = specs.gpuQty;
    if(specs.year)      tr.querySelector('.f-year').value = specs.year;
    var badge = document.getElementById('bs-' + _specModalTarget);
    if (badge) { badge.textContent = 'Done'; badge.className = 'badge b-ok'; }
    // Show brief success feedback then close
    var pa = document.getElementById('specPasteArea');
    pa.style.background = '#e8ffe8';
    setTimeout(function(){ closeSpecModal(); pa.style.background = ''; }, 600);
  } else {
    // Parse failed — highlight textarea to prompt user to check content
    var pa2 = document.getElementById('specPasteArea');
    pa2.style.background = '#fff0f0';
    setTimeout(function(){ pa2.style.background=''; }, 800);
  }
}

// Auto-apply when user pastes into the spec textarea
document.addEventListener('DOMContentLoaded', function() {
  document.getElementById('specPasteArea').addEventListener('paste', function() {
    setTimeout(function() { parseAndApplySpec(); }, 80);
  });
});

// ── Custom date picker (div-based, avoids global table CSS) ──────────────
var _dpY, _dpM;
var _DP_MONTHS = ['January','February','March','April','May','June',
                  'July','August','September','October','November','December'];
var _DP_DAYS   = ['Su','Mo','Tu','We','Th','Fr','Sa'];

// Move dpPop to body on first use so it's never clipped by parent overflow
function dpEnsureRoot() {
  var pop = document.getElementById('dpPop');
  if (pop && pop.parentElement !== document.body) {
    document.body.appendChild(pop);
  }
  return pop;
}

function dpToggle() {
  var pop = dpEnsureRoot();
  if (pop.style.display === 'none') {
    var cur = document.getElementById('f_date').value;
    var d   = cur.match(/^(\d{4})-(\d{2})-(\d{2})$/) ? new Date(cur) : new Date();
    _dpY = d.getFullYear(); _dpM = d.getMonth();
    dpRender();
    var r = document.getElementById('dpBtn').getBoundingClientRect();
    pop.style.top  = (r.bottom + window.scrollY + 4) + 'px';
    pop.style.left = Math.max(4, r.right + window.scrollX - 214) + 'px';
    pop.style.display = '';
    setTimeout(function(){ document.addEventListener('click', dpOutside, true); }, 0);
  } else { dpClose(); }
}

function dpOutside(e) {
  var pop = document.getElementById('dpPop');
  var btn = document.getElementById('dpBtn');
  if (!pop.contains(e.target) && e.target !== btn) dpClose();
}

function dpClose() {
  var pop = document.getElementById('dpPop');
  if (pop) pop.style.display = 'none';
  document.removeEventListener('click', dpOutside, true);
}

function dpNav(delta) {
  _dpM += delta;
  if (_dpM > 11) { _dpM = 0;  _dpY++; }
  if (_dpM < 0)  { _dpM = 11; _dpY--; }
  dpRender();
}

function dpPick(y, m, d) {
  var mm = String(m+1).padStart(2,'0'), dd = String(d).padStart(2,'0');
  document.getElementById('f_date').value = y + '-' + mm + '-' + dd;
  dpClose();
}

function dpRender() {
  var pop   = document.getElementById('dpPop');
  var today = new Date();
  var ty = today.getFullYear(), tm = today.getMonth(), td = today.getDate();
  var cur = document.getElementById('f_date').value;
  var sel = cur.match(/^(\d{4})-(\d{2})-(\d{2})$/)
          ? {y:+cur.slice(0,4), m:+cur.slice(5,7)-1, d:+cur.slice(8,10)} : null;
  var first = new Date(_dpY, _dpM, 1).getDay();
  var total = new Date(_dpY, _dpM+1, 0).getDate();

  // Cell style helper
  var C = 'box-sizing:border-box;width:30px;height:26px;display:flex;align-items:center;' +
          'justify-content:center;border-radius:4px;font-size:12px;cursor:default;';

  // Header
  var h = '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:6px">'
    + '<button onclick="dpNav(-1)" style="border:none;background:none;font-size:18px;cursor:pointer;line-height:1;padding:0 4px;color:#333">&#8249;</button>'
    + '<span style="font-weight:600;font-size:13px">' + _DP_MONTHS[_dpM] + ' ' + _dpY + '</span>'
    + '<button onclick="dpNav(1)"  style="border:none;background:none;font-size:18px;cursor:pointer;line-height:1;padding:0 4px;color:#333">&#8250;</button>'
    + '</div>';

  // Day-of-week row (7 × 30px = 210px)
  h += '<div style="display:flex">';
  _DP_DAYS.forEach(function(day) {
    h += '<div style="' + C + 'color:#999;font-size:11px;cursor:default">' + day + '</div>';
  });
  h += '</div>';

  // Date grid
  h += '<div style="display:flex;flex-wrap:wrap">';
  // Empty cells before first day
  for (var i = 0; i < first; i++) {
    h += '<div style="' + C + '"></div>';
  }
  // Day cells
  for (var d = 1; d <= total; d++) {
    var isToday = (ty===_dpY && tm===_dpM && td===d);
    var isSel   = sel && (sel.y===_dpY && sel.m===_dpM && sel.d===d);
    var bg = isSel ? '#0d6efd' : isToday ? '#e8f0fe' : 'transparent';
    var fg = isSel ? '#fff'    : isToday ? '#0d6efd' : '#333';
    var hw = isSel ? '#0b5ed7' : '#e9ecef';
    h += '<div onclick="dpPick(' + _dpY + ',' + _dpM + ',' + d + ')" '
       + 'onmouseover="this.style.background=\'' + hw + '\'" '
       + 'onmouseout="this.style.background=\'' + bg + '\'" '
       + 'style="' + C + 'background:' + bg + ';color:' + fg + ';cursor:pointer">'
       + d + '</div>';
  }
  h += '</div>';

  // Prev/Next year
  h += '<div style="margin-top:6px;text-align:center;font-size:11px;color:#999">'
     + '<button onclick="dpNav(-12)" style="border:none;background:none;cursor:pointer;color:#666;font-size:11px">&#171; prev yr</button>'
     + '&ensp;'
     + '<button onclick="dpNav(12)"  style="border:none;background:none;cursor:pointer;color:#666;font-size:11px">next yr &#187;</button>'
     + '</div>';

  pop.innerHTML = h;
}

